            [
                'name' =&gt; 'title',
                'contents' =&gt; 'zaedjx'
            ],
            [
                'name' =&gt; 'file',
                'contents' =&gt; fopen('C:\tmp\riskcape_uploads\php9723.tmp', 'r')
