    \"receipt_reference\": \"ytoxmi\",
    \"expense_date\": \"2026-07-18T06:04:11\"
}"
</code></pre></div>


<div class="javascript-example">
    <pre><code class="language-javascript">const url = new URL(
    "http://127.0.0.1:8000/api/v1/expenses/6"
);

const headers = {
    "Content-Type": "application/json",
    "Accept": "application/json",
};

let body = {
    "title": "vwgshl",
    "description": "Molestiae accusantium non pariatur at est.",
    "amount": 33,
    "currency": "u",
    "payment_method": "izxgnx",
    "vendor": "orrobc",
    "receipt_reference": "ytoxmi",
    "expense_date": "2026-07-18T06:04:11"
};

fetch(url, {
    method: "PUT",
    headers,
    body: JSON.stringify(body),
}).then(response =&gt; response.json());</code></pre></div>


<div class="php-example">
    <pre><code class="language-php">$client = new \GuzzleHttp\Client();
$url = 'http://127.0.0.1:8000/api/v1/expenses/6';
$response = $client-&gt;put(
    $url,
    [
        'headers' =&gt; [
            'Content-Type' =&gt; 'application/json',
        ],
        'json' =&gt; [
            'title' =&gt; 'vwgshl',
            'description' =&gt; 'Molestiae accusantium non pariatur at est.',
            'amount' =&gt; 33,
            'currency' =&gt; 'u',
            'payment_method' =&gt; 'izxgnx',
            'vendor' =&gt; 'orrobc',
            'receipt_reference' =&gt; 'ytoxmi',
            'expense_date' =&gt; '2026-07-18T06:04:11',
        ],
    ]
);
$body = $response-&gt;getBody();
print_r(json_decode((string) $body));</code></pre></div>

