                    <h2 id="endpoints-POSTapi-v1-auto-decision--decision_id--override">POST /api/v1/auto-decision/{decision}/override
Staff manual override of an auto-decision.</h2>

<p>
</p>



<span id="example-requests-POSTapi-v1-auto-decision--decision_id--override">
<blockquote>Example request:</blockquote>


<div class="bash-example">
    <pre><code class="language-bash">curl --request POST \
    "http://127.0.0.1:8000/api/v1/auto-decision/6/override" \
    --header "Content-Type: application/json" \
    --data "{
    \"action\": \"manual\",
    \"notes\": \"architecto\"
}"
</code></pre></div>


<div class="javascript-example">
    <pre><code class="language-javascript">const url = new URL(
    "http://127.0.0.1:8000/api/v1/auto-decision/6/override"
);

const headers = {
    "Content-Type": "application/json",
    "Accept": "application/json",
};

let body = {
    "action": "manual",
    "notes": "architecto"
};

fetch(url, {
    method: "POST",
    headers,
    body: JSON.stringify(body),
}).then(response =&gt; response.json());</code></pre></div>


<div class="php-example">
    <pre><code class="language-php">$client = new \GuzzleHttp\Client();
