            'Content-Type' =&gt; 'application/json',
        ],
        'json' =&gt; [
            'name' =&gt; 'vwgshl',
            'email' =&gt; 'hilario.johnson@example.org',
            'username' =&gt; 'xauuiz',
            'phone' =&gt; 'xgnxor',
            'role' =&gt; 'branch_manager',
            'department' =&gt; 'robcyt',
