        'multipart' =&gt; [
            [
                'name' =&gt; 'logo',
                'contents' =&gt; fopen('C:\tmp\riskcape_uploads\phpEF85.tmp', 'r')
            ],
        ],
    ]
);
$body = $response-&gt;getBody();
