    [
        'headers' =&gt; [
            'Content-Type' =&gt; 'multipart/form-data',
        ],
        'multipart' =&gt; [
            [
                'name' =&gt; 'logo',
                'contents' =&gt; fopen('C:\tmp\riskcape_uploads\php1C04.tmp', 'r')
            ],
        ],
    ]
);
$body = $response-&gt;getBody();
print_r(json_decode((string) $body));</code></pre></div>

