                    <h2 id="endpoints-POSTapi-v1-borrowers-kyc-lookup">POST /api/v1/borrowers/kyc-lookup
Look up a ghost user by national ID, TPIN, or company reg number.</h2>

<p>
</p>



<span id="example-requests-POSTapi-v1-borrowers-kyc-lookup">
<blockquote>Example request:</blockquote>


<div class="bash-example">
    <pre><code class="language-bash">curl --request POST \
    "http://127.0.0.1:8000/api/v1/borrowers/kyc-lookup" \
    --header "Content-Type: application/json" \
    --data "{
    \"national_id\": \"architecto\",
    \"tpin_number\": \"architecto\",
    \"company_reg_number\": \"architecto\"
}"
</code></pre></div>


<div class="javascript-example">
    <pre><code class="language-javascript">const url = new URL(
    "http://127.0.0.1:8000/api/v1/borrowers/kyc-lookup"
);

const headers = {
    "Content-Type": "application/json",
    "Accept": "application/json",
};

let body = {
    "national_id": "architecto",
    "tpin_number": "architecto",
    "company_reg_number": "architecto"
};

fetch(url, {
    method: "POST",
    headers,
    body: JSON.stringify(body),
}).then(response =&gt; response.json());</code></pre></div>


<div class="php-example">
    <pre><code class="language-php">$client = new \GuzzleHttp\Client();
$url = 'http://127.0.0.1:8000/api/v1/borrowers/kyc-lookup';
$response = $client-&gt;post(
    $url,
    [
        'headers' =&gt; [
            'Content-Type' =&gt; 'application/json',
        ],
        'json' =&gt; [
            'national_id' =&gt; 'architecto',
            'tpin_number' =&gt; 'architecto',
            'company_reg_number' =&gt; 'architecto',
        ],
    ]
);
$body = $response-&gt;getBody();
print_r(json_decode((string) $body));</code></pre></div>

