                    <h2 id="endpoints-POSTapi-v1-me-kyc-upload">POST api/v1/me/kyc/upload</h2>

<p>
</p>



<span id="example-requests-POSTapi-v1-me-kyc-upload">
<blockquote>Example request:</blockquote>


<div class="bash-example">
    <pre><code class="language-bash">curl --request POST \
    "http://127.0.0.1:8000/api/v1/me/kyc/upload" \
    --header "Content-Type: multipart/form-data" \
    --form "document_type=architecto"\
    --form "expires_at=2056-05-24"\
    --form "file=@C:\tmp\riskcape_uploads\php988A.tmp" </code></pre></div>


<div class="javascript-example">
    <pre><code class="language-javascript">const url = new URL(
    "http://127.0.0.1:8000/api/v1/me/kyc/upload"
);

const headers = {
    "Content-Type": "multipart/form-data",
    "Accept": "application/json",
};

const body = new FormData();
body.append('document_type', 'architecto');
body.append('expires_at', '2056-05-24');
body.append('file', document.querySelector('input[name="file"]').files[0]);

fetch(url, {
    method: "POST",
    headers,
    body,
}).then(response =&gt; response.json());</code></pre></div>


<div class="php-example">
    <pre><code class="language-php">$client = new \GuzzleHttp\Client();
$url = 'http://127.0.0.1:8000/api/v1/me/kyc/upload';
$response = $client-&gt;post(
    $url,
    [
        'headers' =&gt; [
            'Content-Type' =&gt; 'multipart/form-data',
        ],
        'multipart' =&gt; [
            [
                'name' =&gt; 'document_type',
                'contents' =&gt; 'architecto'
            ],
            [
                'name' =&gt; 'expires_at',
                'contents' =&gt; '2056-05-24'
            ],
            [
                'name' =&gt; 'file',
                'contents' =&gt; fopen('C:\tmp\riskcape_uploads\php988A.tmp', 'r')
            ],
        ],
    ]
);
$body = $response-&gt;getBody();
print_r(json_decode((string) $body));</code></pre></div>

