                    <h2 id="endpoints-POSTapi-v1-marketplace-listings--id--express-interest">POST /api/v1/marketplace/listings/{id}/express-interest</h2>

<p>
</p>



<span id="example-requests-POSTapi-v1-marketplace-listings--id--express-interest">
<blockquote>Example request:</blockquote>


<div class="bash-example">
    <pre><code class="language-bash">curl --request POST \
    "http://127.0.0.1:8000/api/v1/marketplace/listings/architecto/express-interest" \
    --header "Content-Type: application/json" \
    --data "{
    \"amount_offered\": 16,
    \"interest_rate\": 25,
    \"message\": \"gshlza\"
}"
</code></pre></div>


<div class="javascript-example">
    <pre><code class="language-javascript">const url = new URL(
    "http://127.0.0.1:8000/api/v1/marketplace/listings/architecto/express-interest"
);

const headers = {
    "Content-Type": "application/json",
    "Accept": "application/json",
};

let body = {
    "amount_offered": 16,
    "interest_rate": 25,
    "message": "gshlza"
};

fetch(url, {
    method: "POST",
    headers,
    body: JSON.stringify(body),
}).then(response =&gt; response.json());</code></pre></div>


<div class="php-example">
    <pre><code class="language-php">$client = new \GuzzleHttp\Client();
$url = 'http://127.0.0.1:8000/api/v1/marketplace/listings/architecto/express-interest';
$response = $client-&gt;post(
    $url,
    [
        'headers' =&gt; [
            'Content-Type' =&gt; 'application/json',
        ],
        'json' =&gt; [
            'amount_offered' =&gt; 16,
            'interest_rate' =&gt; 25,
            'message' =&gt; 'gshlza',
        ],
    ]
);
$body = $response-&gt;getBody();
print_r(json_decode((string) $body));</code></pre></div>

