                    <h2 id="endpoints-PUTapi-v1-landlord-plan-configs--plan-">PUT /v1/landlord/plan-configs/{plan}
Update price and features for the given plan.</h2>

<p>
</p>



<span id="example-requests-PUTapi-v1-landlord-plan-configs--plan-">
<blockquote>Example request:</blockquote>


<div class="bash-example">
    <pre><code class="language-bash">curl --request PUT \
    "http://127.0.0.1:8000/api/v1/landlord/plan-configs/architecto" \
    --header "Content-Type: application/json" \
    --data "{
    \"label\": \"vwgshl\",
    \"description\": \"Molestiae accusantium non pariatur at est.\",
    \"price_zmw\": 33,
    \"is_custom_price\": true,
    \"features\": {
        \"max_users\": 81,
        \"max_branches\": 45,
        \"max_loan_products\": 84,
        \"max_borrowers\": 22,
        \"pwa\": false,
        \"custom_domain\": true,
        \"bulk_operations\": true,
        \"advanced_reports\": false,
        \"collection_management\": false,
        \"marketplace\": true,
        \"disbursement_mobile_money\": true,
        \"tenant_website\": true,
        \"api_access\": true,
        \"exchange_rates\": false,
        \"two_factor_auth\": true,
        \"audit_log\": true
    }
}"
</code></pre></div>


<div class="javascript-example">
    <pre><code class="language-javascript">const url = new URL(
    "http://127.0.0.1:8000/api/v1/landlord/plan-configs/architecto"
);

const headers = {
    "Content-Type": "application/json",
    "Accept": "application/json",
};

let body = {
    "label": "vwgshl",
    "description": "Molestiae accusantium non pariatur at est.",
    "price_zmw": 33,
    "is_custom_price": true,
    "features": {
        "max_users": 81,
        "max_branches": 45,
        "max_loan_products": 84,
        "max_borrowers": 22,
        "pwa": false,
        "custom_domain": true,
        "bulk_operations": true,
        "advanced_reports": false,
        "collection_management": false,
        "marketplace": true,
        "disbursement_mobile_money": true,
        "tenant_website": true,
        "api_access": true,
        "exchange_rates": false,
        "two_factor_auth": true,
        "audit_log": true
    }
};

fetch(url, {
    method: "PUT",
    headers,
    body: JSON.stringify(body),
}).then(response =&gt; response.json());</code></pre></div>


