<div class="bash-example">
    <pre><code class="language-bash">curl --request POST \
    "http://127.0.0.1:8000/api/v1/landlord/platform-settings/branding/logo" \
    --header "Content-Type: multipart/form-data" \
    --form "logo=@C:\tmp\riskcape_uploads\phpD853.tmp" </code></pre></div>


<div class="javascript-example">
    <pre><code class="language-javascript">const url = new URL(
    "http://127.0.0.1:8000/api/v1/landlord/platform-settings/branding/logo"
);

const headers = {
    "Content-Type": "multipart/form-data",
    "Accept": "application/json",
};

const body = new FormData();
body.append('logo', document.querySelector('input[name="logo"]').files[0]);

fetch(url, {
    method: "POST",
    headers,
    body,
}).then(response =&gt; response.json());</code></pre></div>


<div class="php-example">
    <pre><code class="language-php">$client = new \GuzzleHttp\Client();
$url = 'http://127.0.0.1:8000/api/v1/landlord/platform-settings/branding/logo';
$response = $client-&gt;post(
    $url,
    [
        'headers' =&gt; [
            'Content-Type' =&gt; 'multipart/form-data',
        ],
        'multipart' =&gt; [
            [
                'name' =&gt; 'logo',
                'contents' =&gt; fopen('C:\tmp\riskcape_uploads\phpD853.tmp', 'r')
            ],
        ],
    ]
);
$body = $response-&gt;getBody();
